from typing import Dict, Tuple, Optional

class HTTPServer:
    def __init__(self, host: str = '0.0.0.0', port: int = 8080, root_dir: str = './public'):
        self.host = host
        self.port = port
        self.root_dir = os.path.abspath(root_dir)
        self.server_socket = None
        self.keep_alive = True
        self.chunk_size = 8192

        # Ensure root directory exists
        os.makedirs(self.root_dir, exist_ok=True)

    def start(self):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.server_socket.bind((self.host, self.port))
        self.server_socket.listen(5)

        print(f"HTTP/1.1 Server running on http://{self.host}:{self.port}")
        print(f"Serving files from: {self.root_dir}")

        try:
            while True:
                client_socket, addr = self.server_socket.accept()
                self.handle_client(client_socket)
        except KeyboardInterrupt:
            print("\nShutting down server...")
        finally:
            if self.server_socket:
                self.server_socket.close()

    def handle_client(self, client_socket: socket.socket):
        try:
            while True:  # Support keep-alive
                request = self.parse_request(client_socket)
                if not request:
                    break

                method, path, headers, body = request

                # Handle keep-alive
                connection = headers.get('connection', '').lower()
                should_close = connection == 'close' or not self.keep_alive

                if method == 'GET':
                    self.handle_get(client_socket, path, headers, should_close)
                elif method == 'POST':
                    self.handle_post(client_socket, path, headers, body, should_close)
                else:
                    self.send_response(client_socket, 405, b"Method Not Allowed", should_close)

                if should_close:
                    break
        except Exception as e:
            print(f"Error handling client: {e}")
        finally:
            client_socket.close()

    def parse_request(self, client_socket: socket.socket) -> Optional[Tuple]:
        try:
            # Read headers
            data = b''
            while b'\r\n\r\n' not in data:
                chunk = client_socket.recv(4096)
                if not chunk:
                    return None
                data += chunk
                if len(data) > 65536:  # Prevent DoS
                    return None

            headers_part, body_part = data.split(b'\r\n\r\n', 1)
            header_lines = headers_part.decode('utf-8', errors='replace').split('\r\n')

            # Parse request line
            request_line = header_lines[0]
            parts = request_line.split()
            if len(parts) < 3:
                return None
            method, path, version = parts

            if not version.startswith('HTTP/1'):
                return None

            # Parse headers
            headers = {}
            for line in header_lines[1:]:
                if ': ' in line:
                    key, value = line.split(': ', 1)
                    headers[key.lower()] = value.strip()

            # Handle Content-Length
            body = body_part
            content_length = int(headers.get('content-length', 0))
            if content_length > len(body):
                remaining = content_length - len(body)
                while remaining > 0:
                    chunk = client_socket.recv(min(remaining, 8192))
                    if not chunk:
                        break
                    body += chunk
                    remaining -= len(chunk)

            # Handle chunked transfer encoding
            if headers.get('transfer-encoding', '').lower() == 'chunked':
                body = self.parse_chunked(body)

            path = unquote_plus(path.split('?', 1)[0])  # Remove query string
            return method, path, headers, body

        except Exception:
            return None

    def parse_chunked(self, data: bytes) -> bytes:
        result = bytearray()
        i = 0
        while i < len(data):
            # Read chunk size
            chunk_size_end = data.find(b'\r\n', i)
            if chunk_size_end == -1:
                break
            try:
                chunk_size = int(data[i:chunk_size_end], 16)
            except ValueError:
                break

            if chunk_size == 0:
                break

            i = chunk_size_end + 2
            result.extend(data[i:i + chunk_size])
            i += chunk_size + 2  # Skip \r\n

        return bytes(result)

    def handle_get(self, client_socket: socket.socket, path: str, headers: Dict, should_close: bool):
        if path == '/':
            path = '/index.html'

        filepath = self.get_safe_path(path)

        if not os.path.exists(filepath):
            self.send_404(client_socket, should_close)
            return

        if os.path.isdir(filepath):
            filepath = os.path.join(filepath, 'index.html')
            if not os.path.exists(filepath):
                self.send_404(client_socket, should_close)
                return

        try:
            with open(filepath, 'rb') as f:
                content = f.read()

            content_type = mimetypes.guess_type(filepath)[0] or 'application/octet-stream'
            headers_response = {
                'Content-Type': content_type,
                'Content-Length': str(len(content)),
                'Date': self.http_date(),
                'Server': 'RawPythonHTTPServer',
                'Connection': 'close' if should_close else 'keep-alive'
            }
            self.send_response(client_socket, 200, content, should_close, headers_response)
        except Exception:
            self.send_404(client_socket, should_close)

    def handle_post(self, client_socket: socket.socket, path: str, headers: Dict, body: bytes, should_close: bool):
        content_type = headers.get('content-type', '')

        response_body = f"Received POST to {path}\n".encode()
        response_body += f"Content-Type: {content_type}\n".encode()
        response_body += f"Body size: {len(body)} bytes\n".encode()

        if content_type.startswith('application/x-www-form-urlencoded'):
            try:
                form_data = unquote_plus(body.decode('utf-8', errors='replace'))
                response_body += b"\nForm data:\n" + form_data.encode()
            except:
                pass

        headers_response = {
            'Content-Type': 'text/plain',
            'Content-Length': str(len(response_body)),
            'Date': self.http_date(),
            'Server': 'RawPythonHTTPServer',
            'Connection': 'close' if should_close else 'keep-alive'
        }

        self.send_response(client_socket, 200, response_body, should_close, headers_response)

    def get_safe_path(self, path: str) -> str:
        """Prevent directory traversal attacks"""
        clean_path = path.lstrip('/')
        full_path = os.path.join(self.root_dir, clean_path)
        abs_path = os.path.abspath(full_path)

        if not abs_path.startswith(self.root_dir):
            return os.path.join(self.root_dir, '404.html')
        return abs_path

    def send_404(self, client_socket: socket.socket, should_close: bool):
        content = b"<h1>404 Not Found</h1><p>The requested resource was not found.</p>"
        headers = {
            'Content-Type': 'text/html',
            'Content-Length': str(len(content)),
            'Date': self.http_date(),
            'Server': 'RawPythonHTTPServer',
            'Connection': 'close' if should_close else 'keep-alive'
        }
        self.send_response(client_socket, 404, content, should_close, headers)

    def send_response(self, client_socket: socket.socket, status: int, body: bytes, 
                     should_close: bool, headers: Optional[Dict] = None):
        status_messages = {
            200: "OK",
            404: "Not Found",
            405: "Method Not Allowed",
            500: "Internal Server Error"
        }

        status_text = status_messages.get(status, "Unknown")

        response = f"HTTP/1.1 {status} {status_text}\r\n".encode()

        if headers is None:
            headers = {}

        for key, value in headers.items():
            response += f"{key}: {value}\r\n".encode()

        if should_close:
            response += b"Connection: close\r\n"

        response += b"\r\n"
        response += body

        try:
            client_socket.sendall(response)
        except:
            pass

    def http_date(self) -> str:
        return datetime.datetime.utcnow().strftime('%a, %d %b %Y %H:%M:%S GMT')


