        except Exception as e:
            print(f"Error in client handling: {e}")
        finally:
            client_socket.close()

    def receive_all(self, client_socket):
        BUFFER_SIZE = 4096
        request = b''

        # Set a timeout to prevent hanging on incomplete requests
        client_socket.settimeout(1)

        try:
            while True:
                chunk = client_socket.recv(BUFFER_SIZE)
                if not chunk:
                    break
                request += chunk

                # Check if we've reached the end of the headers
                if b'\r\n\r\n' in request:
                    # For GET requests, we're done
                    if not request.startswith(b'POST'):
                        break

                    # For POST, we need to check Content-Length or Transfer-Encoding
                    headers = self.parse_headers(request.split(b'\r\n\r\n')[0].decode())
                    if 'content-length' in headers:
                        content_length = int(headers['content-length'])
                        body_length = len(request.split(b'\r\n\r\n')[1])
                        if body_length >= content_length:
                            break
                    elif 'transfer-encoding' in headers and headers['transfer-encoding'].lower() == 'chunked':
                        if b'0\r\n\r\n' in request:  # End of chunked data
                            break
        except socket.timeout:
            pass  # Timeout reached, proceed with what we have
        except Exception as e:
            print(f"Error receiving data: {e}")
            return b''

        return request

    def parse_request(self, request):
