        return response

    def error_response(self, status_code, status_message):
        error_page = f"""
        <html>
            <head>
                <title>{status_code} {status_message}</title>
            </head>
            <body>
                <h1>{status_code} {status_message}</h1>
            </body>
        </html>
        """

        headers = {
            'Content-Type': 'text/html',
            'Connection': 'close'
        }

        return self.build_response(status_code, status_message, headers, error_page.encode())

if __name__ == '__main__':
    server = HTTPServer()
    server.start()
